import { useContext } from "react";
import Login from "./components/Login";
import Chat from "./components/Chat";
import { AuthContext } from "./context/AuthContext";

function App() {
    const { token } = useContext(AuthContext);
    return (
        <div>
            {
                token
                    ?
                    <Chat />
                    :
                    <Login />
            }
        </div>
    );
}

export default App;
